import{_ as i,o as e,c as l,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"时","description":"时不是钟表时间，而是事势发展到当下这一刻的合宜与不合宜。","frontmatter":{"title":"时","description":"时不是钟表时间，而是事势发展到当下这一刻的合宜与不合宜。","category":"concept","aliases":["时","易经时","shi"]},"headers":[],"relativePath":"yijing/basics/concepts/shi.md","filePath":"yijing/basics/concepts/shi.md","lastUpdated":1777132262000}'),o={name:"yijing/basics/concepts/shi.md"};function r(s,a,n,c,h,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="时" tabindex="-1">时 <a class="header-anchor" href="#时" aria-label="Permalink to &quot;时&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>《易经》里的“时”，更接近时机、时势、时宜，而不是简单的时间刻度。</p><p>它关心的是：</p><ul><li>现在处在什么阶段</li><li>这个位置该不该动</li><li>这时做什么才合宜</li><li>同样的行为，在不同阶段为什么结果不同</li></ul><p>所以读《易》离不开“时”。脱离时，很多吉凶判断都会变硬。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>把时读成宿命安排</li><li>以为《易经》只是在说“顺其自然，什么都别做”</li><li>只看对错，不看时机是否成熟</li></ul><p>《易》讲时，不是让人被动等，而是提醒人看清当下所处之势，再决定进退。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《彖传》《象传》中常见“时义”“时行”“时止”等说法。</li><li>很多卦的核心，不在永恒原则，而在某一时段如何应对。</li><li>同一德性在不同“时”里，表现方式也会变化：有时宜进，有时宜守，有时宜退。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可结合“时中”“时行则行，时止则止”之类的阅读体会继续补写。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/bian-yi">变易</a></li><li><a href="/Dao/yijing/basics/concepts/zhong-zheng">中正</a></li><li><a href="/Dao/yijing/basics/concepts/wei">位</a></li><li><a href="/Dao/topics/bian-yi">专题：变易</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《彖传》</li><li>《系辞上传》</li></ul>',17)])])}const b=i(o,[["render",r]]);export{u as __pageData,b as default};
